class Solution:
    def scoreValidator(self, events):
        score = 0
        counter = 0
        for e in events:
            if counter == 10:
                break
            if e == 'W':
                counter += 1
            elif e == 'WD' or e == 'NB':
                score += 1
            else:
                score += int(e)
        return [score, counter]

