var scoreValidator = function(events) {
    let score = 0, counter = 0;
    for (const e of events) {
        if (counter === 10) break;
        if (e === 'W') counter += 1;
        else if (e === 'WD' || e === 'NB') score += 1;
        else score += parseInt(e, 10);
    }
    return [score, counter];
};
